// Product declaration reference data for HS code lookup
// 500 unique items for cross-border shipping
// Risk levels: normal | needs-confirm | high-risk | restricted
// Generated: 2026-05-08 (deduped + quality checked)

export interface ProductDecl {
  name: string;
  aliases: string[];
  nameEn: string;
  material: string;
  usage: string;
  riskLevel: 'normal' | 'needs-confirm' | 'high-risk' | 'restricted';
  hsCandidates: string[];
  notes: string;
  officialUrl: string;
  thirdPartyUrl?: string;
}

const labelMap: Record<string, string> = {
  'normal': '普通货参考',
  'needs-confirm': '需确认属性',
  'high-risk': '高风险合规确认',
  'restricted': '明显受限 / 高管制风险',
};

const mk = (name: string, aliases: string[], nameEn: string, material: string, usage: string, hsCandidates: string[], notes: string, riskLevel: ProductDecl['riskLevel'] = 'normal'): ProductDecl => ({
  name, aliases, nameEn, material, usage, riskLevel, hsCandidates, notes,
  officialUrl: 'https://www.customs.gov.cn',
  thirdPartyUrl: 'https://www.hscode.net',
});

type BatchItem = { name: string; aliases: string[]; nameEn: string; material: string; usage: string; hs: string[]; notes: string; riskLevel?: ProductDecl['riskLevel'] };
const batch = (risk: ProductDecl['riskLevel'], items: BatchItem[]): ProductDecl[] =>
  items.map(i => mk(i.name, i.aliases, i.nameEn, i.material, i.usage, i.hs, i.notes, i.riskLevel ?? risk));

